type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldMeta {
  min: number;
  max: number;
}

const FIELD_META: Record<CronField, FieldMeta> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both represent Sunday
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseNumber(token: string, context: string): number {
  const n = Number(token);
  if (!Number.isInteger(n) || token.trim() === "") {
    throw new SyntaxError(`Invalid numeric token "${token}" in field "${context}"`);
  }
  return n;
}

function expandRange(start: number, end: number, step: number, field: CronField): number[] {
  const { min, max } = FIELD_META[field];
  assertInRange(start, min, max, field);
  assertInRange(end,   min, max, field);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds range end ${end} in field "${field}"`
    );
  }

  if (step < 1) {
    throw new RangeError(`Step value ${step} must be >= 1 in field "${field}"`);
  }

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_META[field];

  // Step on wildcard: */n
  const wildcardStepMatch = segment.match(/^\*\/(\d+)$/);
  if (wildcardStepMatch) {
    const step = parseNumber(wildcardStepMatch[1], field);
    return expandRange(min, max, step, field);
  }

  // Wildcard: *
  if (segment === "*") {
    return expandRange(min, max, 1, field);
  }

  // Range with optional step: n-m or n-m/s
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseNumber(rangeMatch[1], field);
    const end   = parseNumber(rangeMatch[2], field);
    const step  = rangeMatch[3] !== undefined ? parseNumber(rangeMatch[3], field) : 1;
    return expandRange(start, end, step, field);
  }

  // Step on a specific start: n/s (e.g. 5/15 means 5, 20, 35, ...)
  const startStepMatch = segment.match(/^(\d+)\/(\d+)$/);
  if (startStepMatch) {
    const start = parseNumber(startStepMatch[1], field);
    const step  = parseNumber(startStepMatch[2], field);
    return expandRange(start, max, step, field);
  }

  // Plain number
  if (/^\d+$/.test(segment)) {
    const n = parseNumber(segment, field);
    assertInRange(n, min, max, field);
    return [n];
  }

  throw new SyntaxError(`Unrecognised cron segment "${segment}" in field "${field}"`);
}

function parseField(expr: string, field: CronField): number[] {
  const segments = expr.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty expression for field "${field}"`);
  }

  const rawValues = segments.flatMap((seg) => parseSegment(seg.trim(), field));

  // Normalise dayOfWeek: treat 7 as Sunday (0)
  const normalised = field === "dayOfWeek"
    ? rawValues.map((v) => (v === 7 ? 0 : v))
    : rawValues;

  // Deduplicate and sort
  const unique = Array.from(new Set(normalised)).sort((a, b) => a - b);
  return unique;
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  }, // 7 = Sunday alias
] as const;

const PURE_INTEGER_RE = /^\d+$/;

function assertInteger(raw: string, context: string): number {
  if (!PURE_INTEGER_RE.test(raw)) {
    throw new Error(`Expected an integer but got "${raw}" in ${context}`);
  }
  const n = parseInt(raw, 10);
  if (isNaN(n)) {
    throw new Error(`Failed to parse "${raw}" as integer in ${context}`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig, hint: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of range [${config.min}–${config.max}] in ${config.name} (${hint})`
    );
  }
}

function generateRange(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseAtom(atom: string, config: FieldConfig): number[] {
  if (!atom || atom.trim() === "") {
    throw new Error(`Empty atom expression in field "${config.name}"`);
  }
  const trimmed = atom.trim();

  // Step with optional base: * / N  |  start / N  |  start-end / N
  if (trimmed.includes("/")) {
    const slashIdx = trimmed.indexOf("/");
    const base = trimmed.slice(0, slashIdx).trim();
    const stepRaw = trimmed.slice(slashIdx + 1).trim();

    if (!stepRaw) {
      throw new Error(`Missing step value after "/" in field "${config.name}": "${trimmed}"`);
    }
    const step = assertInteger(stepRaw, `step of "${config.name}"`);
    if (step <= 0) {
      throw new RangeError(`Step must be positive, got ${step} in field "${config.name}"`);
    }

    if (base === "*") {
      return generateRange(config.min, config.max, step);
    }

    if (base.includes("-")) {
      const [startRaw, endRaw] = splitRange(base, config);
      const start = assertInteger(startRaw, `range-step start of "${config.name}"`);
      const end   = assertInteger(endRaw,   `range-step end of "${config.name}"`);
      assertInRange(start, config, "range-step start");
      assertInRange(end,   config, "range-step end");
      if (start > end) {
        throw new RangeError(`Range start ${start} exceeds end ${end} in field "${config.name}"`);
      }
      return generateRange(start, end, step);
    }

    const start = assertInteger(base, `step-base of "${config.name}"`);
    assertInRange(start, config, "step base");
    return generateRange(start, config.max, step);
  }

  // Plain range: N-M
  if (trimmed.includes("-")) {
    const [startRaw, endRaw] = splitRange(trimmed, config);
    const start = assertInteger(startRaw, `range start of "${config.name}"`);
    const end   = assertInteger(endRaw,   `range end of "${config.name}"`);
    assertInRange(start, config, "range start");
    assertInRange(end,   config, "range end");
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in field "${config.name}"`);
    }
    return generateRange(start, end, 1);
  }

  // Wildcard
  if (trimmed === "*") {
    return generateRange(config.min, config.max, 1);
  }

  // Plain integer
  const value = assertInteger(trimmed, `value of "${config.name}"`);
  assertInRange(value, config, "literal");
  return [value];
}

function splitRange(expr: string, config: FieldConfig): [string, string] {
  const dashIdx = expr.indexOf("-");
  if (dashIdx === -1) {
    throw new Error(`Expected a range "N-M" but got "${expr}" in field "${config.name}"`);
  }
  const start = expr.slice(0, dashIdx).trim();
  const end   = expr.slice(dashIdx + 1).trim();
  if (!start || !end) {
    throw new Error(`Malformed range "${expr}" in field "${config.name}"`);
  }
  return [start, end];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw === undefined || raw === null || raw.trim() === "") {
    throw new Error(`Field "${config.name}" is missing or empty`);
  }

  const parts = raw.split(",");
  if (parts.length === 0) {
    throw new Error(`Field "${config.name}" produced no parseable parts`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) {
      throw new Error(`Empty segment in comma-separated list for field "${config.name}": "${raw}"`);
    }
    for (const v of parseAtom(trimmed, config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("Cron expression must not be empty");
  }

  // Guard against control characters and obvious injection attempts
  if (/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/.test(trimmed)) {
    throw new Error("Cron expression contains invalid control characters");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `but got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;
    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      flattenObject(value as Record<string, unknown>, path, result);
    } else {
      result[path] = value;
    }
  }
  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { maxDepth?: number; arrayHandling?: "stringify" | "flatten" | "preserve" } = {}
): FlatObject {
  const { maxDepth = 64, arrayHandling = "preserve" } = options;

  if (input === null || input === undefined) {
    throw new TypeError(`flattenObject: input must be a non-null object, got ${input}`);
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: input must be a plain object, got ${Array.isArray(input) ? "array" : typeof input}`
    );
  }

  if (maxDepth < 1 || !Number.isInteger(maxDepth) || maxDepth > 1000) {
    throw new RangeError(`flattenObject: maxDepth must be an integer between 1 and 1000, got ${maxDepth}`);
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject: exceeded maxDepth of ${maxDepth} at key "${prefix}". Possible circular structure or deeply nested object.`
      );
    }

    if (isPlainObject(current)) {
      if (seen.has(current as object)) {
        throw new TypeError(
          `flattenObject: circular reference detected at key "${prefix}"`
        );
      }

      seen.add(current as object);

      const keys = Object.keys(current);

      if (keys.length === 0) {
        // Empty object: preserve as empty string sentinel only if there's a prefix
        if (prefix !== "") {
          result[prefix] = undefined;
        }
        seen.delete(current as object);
        return;
      }

      for (const key of keys) {
        if (key === "") {
          throw new Error(
            `flattenObject: empty string keys are not supported (found at prefix "${prefix}")`
          );
        }
        if (key.includes(".")) {
          throw new Error(
            `flattenObject: keys containing "." are ambiguous and not supported (key "${key}" at prefix "${prefix}")`
          );
        }

        const nextPrefix = prefix === "" ? key : `${prefix}.${key}`;
        const value = (current as NestedObject)[key];
        recurse(value, nextPrefix, depth + 1);
      }

      seen.delete(current as object);
    } else if (Array.isArray(current)) {
      switch (arrayHandling) {
        case "stringify":
          result[prefix] = JSON.stringify(current);
          break;
        case "flatten":
          if (current.length === 0) {
            result[prefix] = undefined;
          }
          for (let i = 0; i < current.length; i++) {
            recurse(current[i], `${prefix}.${i}`, depth + 1);
          }
          break;
        case "preserve":
        default:
          result[prefix] = JSON.stringify(current);
          break;
      }
    } else {
      const primitive = current as Primitive;
      result[prefix] = primitive;
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | Array<unknown> | Date | RegExp | Function;

type FlattenedObject = Record<string, FlatValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: Record<string, unknown>,
  prefix = "",
  seen = new WeakSet<object>()
): FlattenedObject {
  if (seen.has(input)) {
    throw new TypeError(`Circular reference detected at key: "${prefix}"`);
  }
  seen.add(input);

  const result: FlattenedObject = {};

  for (const [key, value] of Object.entries(input)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, fullKey, seen);
      if (Object.keys(nested).length === 0) {
        // Preserve empty objects as their own key with empty-object sentinel
        result[fullKey] = undefined;
      } else {
        Object.assign(result, nested);
      }
    } else {
      result[fullKey] = value as FlatValue;
    }
  }

  seen.delete(input);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, path, result);
    } else {
      result[path] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const [k, v] of Object.entries(obj)) {
    const key = prefix ? `${prefix}.${k}` : k;
    if (v !== null && typeof v === "object" && !Array.isArray(v))
      flattenObject(v as Record<string, unknown>, key, result);
    else result[key] = v;
  }
  return result;
}

type CronField = {
  min: number;
  max: number;
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELDS: Array<{ name: keyof ParsedCron; min: number; max: number }> = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
];

function assertInRange(value: number, field: CronField, raw: string): void {
  if (value < field.min || value > field.max) {
    throw new RangeError(
      `Value ${value} out of range [${field.min}, ${field.max}] in expression "${raw}"`
    );
  }
}

function parseStep(expr: string, field: CronField): number[] {
  const [base, stepStr] = expr.split("/");
  const step = parseInt(stepStr, 10);

  if (isNaN(step) || step < 1) {
    throw new SyntaxError(`Invalid step value in "${expr}"`);
  }

  let start = field.min;
  let end = field.max;

  if (base !== "*") {
    if (base.includes("-")) {
      const [lo, hi] = parseRangeBounds(base, field);
      start = lo;
      end = hi;
    } else {
      start = parseInt(base, 10);
      if (isNaN(start)) throw new SyntaxError(`Invalid step base in "${expr}"`);
      assertInRange(start, field, expr);
    }
  }

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseRangeBounds(expr: string, field: CronField): [number, number] {
  const parts = expr.split("-");
  if (parts.length !== 2) throw new SyntaxError(`Invalid range "${expr}"`);

  const lo = parseInt(parts[0], 10);
  const hi = parseInt(parts[1], 10);

  if (isNaN(lo) || isNaN(hi)) {
    throw new SyntaxError(`Non-numeric range bounds in "${expr}"`);
  }
  if (lo > hi) {
    throw new RangeError(`Range start ${lo} exceeds end ${hi} in "${expr}"`);
  }

  assertInRange(lo, field, expr);
  assertInRange(hi, field, expr);

  return [lo, hi];
}

function parseRange(expr: string, field: CronField): number[] {
  const [lo, hi] = parseRangeBounds(expr, field);
  return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
}

function parseSegment(expr: string, field: CronField): number[] {
  if (expr === "*") {
    return Array.from(
      { length: field.max - field.min + 1 },
      (_, i) => field.min + i
    );
  }

  if (expr.includes("/")) {
    return parseStep(expr, field);
  }

  if (expr.includes("-")) {
    return parseRange(expr, field);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Unrecognized cron segment "${expr}"`);
  }
  assertInRange(value, field, expr);
  return [value];
}

function parseFieldExpression(expr: string, field: CronField): number[] {
  const segments = expr.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field expression "${expr}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Treat 7 as equivalent to 0 (both represent Sunday)
  const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${parts.length} in "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELDS.length; i++) {
    const { name, min, max } = FIELDS[i];
    const field: CronField = { min, max };
    let values = parseFieldExpression(parts[i], field);

    if (name === "dayOfWeek") {
      values = normalizeDayOfWeek(values);
    }

    result[name] = values;
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const range = (from: number, to: number, step = 1): number[] =>
  Array.from({ length: Math.floor((to - from) / step) + 1 }, (_, i) => from + i * step);

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  return value;
};

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step: ${stepStr}`);
    const from = base === "*" ? min : clamp(parseInt(base, 10), min, max);
    return range(from, max, step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);
    if (start > end) throw new RangeError(`Invalid range: ${segment}`);
    return range(start, end);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid token: ${segment}`);
  return [clamp(value, min, max)];
};

const parseField = (expr: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];
  const values = expr.split(",").flatMap(seg => parseSegment(seg.trim(), min, max));
  return [...new Set(values)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronExpression => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);

  const [minute, hour, dayOfMonth, month, dayOfWeek] = (
    ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as CronField[]
  ).map((field, i) => parseField(fields[i], field));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) {
      result[prefix] = obj as Primitive;
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = Record<string, Primitive>;

const flattenObject = (
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject =>
  Object.entries(obj).reduce((acc, [key, value]) => {
    const path = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, path, acc);
    } else {
      acc[path] = value as Primitive;
    }

    return acc;
  }, result);

export default flattenObject;

const FIELD_RANGES = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
} as const;

type Field = keyof typeof FIELD_RANGES;

const FIELDS: Field[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function parseField(expr: string, min: number, max: number): number[] {
  if (expr === "*") return Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${expr}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes(",")) {
    return [...new Set(expr.split(",").flatMap(e => parseField(e, min, max)))].sort((a, b) => a - b);
  }

  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map(n => parseInt(n, 10));
    if (isNaN(lo) || isNaN(hi) || lo > hi) throw new Error(`Invalid range: ${expr}`);
    if (lo < min || hi > max) throw new Error(`Range ${expr} out of bounds [${min},${max}]`);
    return Array.from({ length: hi - lo + 1 }, (_, i) => i + lo);
  }

  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${expr}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min},${max}]`);
  return [n];
}

export default function parseCron(cron: string): Record<Field, number[]> {
  const parts = cron.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  return Object.fromEntries(
    FIELDS.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, parseField(parts[i], min, max)];
    })
  ) as Record<Field, number[]>;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment "${segment}" for field "${field}"`);
    }
    let rangeMin = min;
    let rangeMax = max;
    if (rangePart !== "*") {
      const dashIdx = rangePart.indexOf("-");
      if (dashIdx === -1) {
        rangeMin = parseInt(rangePart, 10);
        rangeMax = max;
      } else {
        rangeMin = parseInt(rangePart.slice(0, dashIdx), 10);
        rangeMax = parseInt(rangePart.slice(dashIdx + 1), 10);
      }
    }
    if (isNaN(rangeMin) || isNaN(rangeMax)) {
      throw new Error(`Invalid range in segment "${segment}" for field "${field}"`);
    }
    if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
      throw new Error(`Range ${rangeMin}-${rangeMax} out of bounds [${min}-${max}] for field "${field}"`);
    }
    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const lo = parseInt(segment.slice(0, dashIdx), 10);
    const hi = parseInt(segment.slice(dashIdx + 1), 10);
    if (isNaN(lo) || isNaN(hi)) {
      throw new Error(`Invalid range "${segment}" for field "${field}"`);
    }
    if (lo < min || hi > max || lo > hi) {
      throw new Error(`Range ${lo}-${hi} out of bounds [${min}-${max}] for field "${field}"`);
    }
    return expandRange(lo, hi);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}" for field "${field}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}] for field "${field}"`);
  }
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  // Comma-separated list
  const parts = expression.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    const expanded = parseSegment(part.trim(), field);
    for (const v of expanded) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const result = {} as ParsedCron;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(`Expected integer, got "${trimmed}" in field "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function range(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function deduplicate(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard base: */N
  if (segment.startsWith("*/")) {
    const stepStr = segment.slice(2);
    const step = parseInteger(stepStr, fieldName);
    if (step <= 0) {
      throw new RangeError(`Step value must be positive, got ${step} in field "${fieldName}"`);
    }
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  // Range with optional step: N-M or N-M/S
  if (segment.includes("-")) {
    const slashIndex = segment.indexOf("/");
    const rangePart = slashIndex !== -1 ? segment.slice(0, slashIndex) : segment;
    const stepPart  = slashIndex !== -1 ? segment.slice(slashIndex + 1) : null;

    const dashIndex = rangePart.indexOf("-");
    const fromStr = rangePart.slice(0, dashIndex);
    const toStr   = rangePart.slice(dashIndex + 1);

    const from = parseInteger(fromStr, fieldName);
    const to   = parseInteger(toStr,   fieldName);

    assertInRange(from, min, max, fieldName);
    assertInRange(to,   min, max, fieldName);

    if (from > to) {
      throw new RangeError(
        `Range start ${from} exceeds end ${to} in field "${fieldName}"`
      );
    }

    if (stepPart !== null) {
      const step = parseInteger(stepPart, fieldName);
      if (step <= 0) {
        throw new RangeError(`Step value must be positive, got ${step} in field "${fieldName}"`);
      }
      const values: number[] = [];
      for (let i = from; i <= to; i += step) values.push(i);
      return values;
    }

    return range(from, to);
  }

  // Plain number
  const value = parseInteger(segment, fieldName);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, config: FieldConfig, fieldName: string): number[] {
  const segments = expression.split(",");

  if (segments.length === 0) {
    throw new SyntaxError(`Empty field expression for "${fieldName}"`);
  }

  const values = segments.flatMap((segment) => {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${fieldName}"`);
    }
    return parseSegment(trimmed, config, fieldName);
  });

  return deduplicate(values);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config    = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(parts[i], config, fieldName);
  }

  return result;
}

const FIELD_RANGES = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function parseField(expr: string, min: number, max: number): number[] {
  const clamp = (n: number) => {
    if (n < min || n > max) throw new RangeError(`Value ${n} out of range [${min}, ${max}]`);
    return n;
  };

  if (expr === "*") return Array.from({ length: max - min + 1 }, (_, i) => min + i);

  if (expr.includes(",")) return [...new Set(expr.split(",").flatMap(p => parseField(p, min, max)))].sort((a, b) => a - b);

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${expr}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${expr}`);
    const [start, end] = rangePart.includes("-")
      ? rangePart.split("-").map(n => clamp(parseInt(n, 10)))
      : [clamp(parseInt(rangePart, 10)), max];
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  if (expr.includes("-")) {
    const [start, end] = expr.split("-").map(n => clamp(parseInt(n, 10)));
    if (start > end) throw new RangeError(`Invalid range: ${expr}`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid cron field: ${expr}`);
  return [clamp(n)];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);
  const fields = Object.keys(FIELD_RANGES) as FieldName[];
  return Object.fromEntries(
    fields.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, parseField(parts[i], min, max)];
    })
  ) as CronResult;
}

type Primitive = string | number | boolean | null | undefined;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

type FlatObject = Record<string, Primitive>;

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) {
    return result;
  }

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, flatKey, result);
    } else {
      result[flatKey] = Array.isArray(value)
        ? (value as unknown as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = Record<string, Primitive | unknown[]>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  input: unknown,
  prefix: string,
  result: FlatObject,
  visited: WeakSet<object>,
  depth: number,
  maxDepth: number
): void {
  if (depth > maxDepth) {
    throw new RangeError(
      `Maximum flattening depth of ${maxDepth} exceeded at key "${prefix}". Possible circular structure or excessively deep object.`
    );
  }

  if (!isPlainObject(input)) {
    result[prefix] = input as Primitive | unknown[];
    return;
  }

  if (visited.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix}".`
    );
  }

  visited.add(input as object);

  const keys = Object.keys(input as object);

  if (keys.length === 0) {
    // Empty object: store as-is if it has a prefix, otherwise result stays empty
    if (prefix !== "") {
      result[prefix] = {} as unknown as Primitive;
    }
    visited.delete(input as object);
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    if (key === "") {
      throw new TypeError(
        `Empty string key encountered at prefix "${prefix}". Cannot safely construct dot-notation path.`
      );
    }

    if (key.includes(".")) {
      throw new TypeError(
        `Key "${key}" at prefix "${prefix}" contains a dot, which would produce ambiguous dot-notation output.`
      );
    }

    const nextPrefix = prefix === "" ? key : `${prefix}.${key}`;
    const value = (input as Record<string, unknown>)[key];

    flattenObjectInternal(value, nextPrefix, result, visited, depth + 1, maxDepth);
  }

  visited.delete(input as object);
}

export default function flattenObject(
  input: unknown,
  options: { maxDepth?: number } = {}
): FlatObject {
  if (input === null || input === undefined) {
    throw new TypeError(
      `flattenObject requires a non-null object, received: ${input}`
    );
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject requires a plain object, received: ${Object.prototype.toString.call(input)}`
    );
  }

  const maxDepth = options.maxDepth ?? 100;

  if (
    typeof maxDepth !== "number" ||
    !Number.isFinite(maxDepth) ||
    maxDepth < 1 ||
    !Number.isInteger(maxDepth)
  ) {
    throw new RangeError(
      `options.maxDepth must be a positive integer, received: ${maxDepth}`
    );
  }

  const result: FlatObject = {};
  const visited = new WeakSet<object>();

  flattenObjectInternal(input, "", result, visited, 0, maxDepth);

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Record<CronField, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

const FIELD_ORDER: ReadonlyArray<CronField> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} in "${context}" is outside the valid range [${min}, ${max}]`
    );
  }
}

function parseStrictInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(
      `Expected a non-negative integer in "${context}", got: "${raw}"`
    );
  }
  const parsed = parseInt(trimmed, 10);
  if (isNaN(parsed)) {
    throw new TypeError(`Failed to parse integer in "${context}": "${raw}"`);
  }
  return parsed;
}

function expandRange(start: number, end: number, step: number, context: string): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step must be a positive integer in "${context}", got: ${step}`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} must be <= end ${end} in "${context}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (!segment || segment.trim() === "") {
    throw new SyntaxError("Cron segment cannot be empty");
  }

  // Step value: */step  |  start-end/step  |  start/step
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression (multiple slashes): "${segment}"`);
    }
    const [rangePart, stepStr] = slashParts;
    const step = parseStrictInteger(stepStr, segment);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer in: "${segment}"`);
    }

    if (rangePart === "*") {
      return expandRange(min, max, step, segment);
    }

    if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range in step expression: "${segment}"`);
      }
      const start = parseStrictInteger(dashParts[0], segment);
      const end   = parseStrictInteger(dashParts[1], segment);
      assertInRange(start, min, max, segment);
      assertInRange(end,   min, max, segment);
      return expandRange(start, end, step, segment);
    }

    // start/step — expand from start to field max
    const start = parseStrictInteger(rangePart, segment);
    assertInRange(start, min, max, segment);
    return expandRange(start, max, step, segment);
  }

  // Wildcard — all values in range
  if (segment === "*") {
    return expandRange(min, max, 1, segment);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range expression (multiple dashes): "${segment}"`);
    }
    const start = parseStrictInteger(dashParts[0], segment);
    const end   = parseStrictInteger(dashParts[1], segment);
    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} must be <= end ${end} in: "${segment}"`
      );
    }
    return expandRange(start, end, 1, segment);
  }

  // Single number
  const num = parseStrictInteger(segment, segment);
  assertInRange(num, min, max, segment);
  return [num];
}

function parseField(fieldStr: string, config: FieldConfig): number[] {
  if (!fieldStr || fieldStr.trim() === "") {
    throw new SyntaxError("Cron field cannot be empty");
  }

  const segments = fieldStr.split(",");
  const valueSet = new Set<number>();

  for (const rawSegment of segments) {
    const segment = rawSegment.trim();
    if (segment === "") {
      throw new SyntaxError(
        `Empty segment (trailing/double comma?) in cron field: "${fieldStr}"`
      );
    }
    const values = parseSegment(segment, config.min, config.max);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  if (valueSet.size === 0) {
    throw new RangeError(`Cron field "${fieldStr}" produced no valid values`);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

/**
 * Normalize dayOfWeek: both 0 and 7 represent Sunday in standard cron.
 * Map 7 → 0 and deduplicate.
 */
function normalizeDayOfWeek(values: number[]): number[] {
  const normalized = new Set<number>(
    values.map((v) => (v === 7 ? 0 : v))
  );
  return Array.from(normalized).sort((a, b) => a - b);
}

/**
 * Parse a 5-field cron expression into a structured object containing
 * arrays of all matching values for each field.
 *
 * Field order: minute hour dayOfMonth month dayOfWeek
 * Valid ranges: minute 0-59, hour 0-23, dayOfMonth 1-31, month 1-12, dayOfWeek 0-7
 *
 * @throws {TypeError}   for non-string input or non-integer values
 * @throws {SyntaxError} for malformed expression structure
 * @throws {RangeError}  for values outside their valid field ranges
 */
export default function parseCron(expression: string): CronExpression {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a non-null, non-undefined string");
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, received: ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression cannot be an empty string");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 whitespace-separated fields, ` +
      `got ${fields.length} in: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  return {
    minute:     parseField(minuteStr, FIELD_CONFIGS.minute),
    hour:       parseField(hourStr,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domStr,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthStr,  FIELD_CONFIGS.month),
    dayOfWeek:  normalizeDayOfWeek(
                  parseField(dowStr, FIELD_CONFIGS.dayOfWeek)
                ),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELDS: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const range = (from: number, to: number, step = 1): number[] =>
  Array.from({ length: Math.floor((to - from) / step) + 1 }, (_, i) => from + i * step);

const clamp = (n: number, min: number, max: number) => {
  if (n < min || n > max) throw new RangeError(`Value ${n} out of range [${min}, ${max}]`);
  return n;
};

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);
    const [from, to] = rangePart === "*" ? [min, max] : rangePart.split("-").map(Number);
    return range(clamp(from, min, max), clamp(to ?? from, min, max), step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [from, to] = segment.split("-").map(Number);
    return range(clamp(from, min, max), clamp(to, min, max));
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Literal
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${segment}`);
  return [clamp(n, min, max)];
};

const parseField = (expr: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  const values = expr
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), min, max));

  return [...new Set(values)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  return Object.fromEntries(
    FIELDS.map((field, i) => [field, parseField(parts[i], field)])
  ) as CronResult;
};

export default parseCron;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: Array<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(start: number, end: number, step = 1): number[] {
  if (step < 1) {
    throw new Error(`Step must be >= 1, got ${step}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} is out of range [${config.min}, ${config.max}] in field "${context}"`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  // Wildcard: *
  if (segment === "*") {
    return rangeArray(config.min, config.max);
  }

  // Step on wildcard: */N
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) {
      throw new Error(`Step value must be >= 1 in field "${fieldName}"`);
    }
    return rangeArray(config.min, config.max, step);
  }

  // Range with optional step: N-M or N-M/S
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    const step  = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;

    assertInRange(start, config, fieldName);
    assertInRange(end,   config, fieldName);

    if (start > end) {
      throw new Error(
        `Range start ${start} is greater than end ${end} in field "${fieldName}"`
      );
    }
    if (step < 1) {
      throw new Error(`Step value must be >= 1 in field "${fieldName}"`);
    }

    return rangeArray(start, end, step);
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    assertInRange(value, config, fieldName);
    return [value];
  }

  throw new Error(`Unrecognized cron segment "${segment}" in field "${fieldName}"`);
}

function parseField(expression: string, config: FieldConfig, fieldName: string): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new Error(`Empty field expression for "${fieldName}"`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed.length === 0) {
      throw new Error(`Empty segment in field "${fieldName}"`);
    }
    const values = parseSegment(trimmed, config, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config    = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(parts[i], config, fieldName);
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldDefinition = {
  name: keyof CronExpression;
  min: number;
  max: number;
};

const FIELD_DEFINITIONS: FieldDefinition[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  }, // 0 and 7 both represent Sunday
];

function buildRange(start: number, end: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function assertBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}, ${max}] in expression "${context}"`
    );
  }
}

function parseSimpleValue(raw: string, min: number, max: number, context: string): number {
  const n = parseInt(raw, 10);
  if (isNaN(n) || String(n) !== raw.trim()) {
    throw new SyntaxError(`Expected an integer but got "${raw}" in expression "${context}"`);
  }
  assertBounds(n, min, max, context);
  return n;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const slashIndex = segment.lastIndexOf("/");
    const rangePart = segment.slice(0, slashIndex);
    const stepPart  = segment.slice(slashIndex + 1);

    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Step value must be a positive integer in "${segment}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-");
      rangeStart = parseSimpleValue(s, min, max, segment);
      rangeEnd   = parseSimpleValue(e, min, max, segment);
    } else {
      rangeStart = parseSimpleValue(rangePart, min, max, segment);
      rangeEnd   = max;
    }

    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start (${rangeStart}) exceeds range end (${rangeEnd}) in "${segment}"`
      );
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard: *
  if (segment === "*") {
    return buildRange(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const s = segment.slice(0, dashIndex);
    const e = segment.slice(dashIndex + 1);
    const start = parseSimpleValue(s, min, max, segment);
    const end   = parseSimpleValue(e, min, max, segment);
    if (start > end) {
      throw new RangeError(
        `Range start (${start}) exceeds range end (${end}) in "${segment}"`
      );
    }
    return buildRange(start, end);
  }

  // Single value
  return [parseSimpleValue(segment, min, max, segment)];
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list: each item may itself be a wildcard, range, step, or number
  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const value of parseSegment(trimmed, min, max)) {
      valueSet.add(value);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, but got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_DEFINITIONS.length; i++) {
    const { name, min, max } = FIELD_DEFINITIONS[i];
    result[name] = parseField(fields[i], min, max);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const range = (from: number, to: number, step = 1): number[] =>
  Array.from({ length: Math.floor((to - from) / step) + 1 }, (_, i) => from + i * step);

const clamp = (n: number, min: number, max: number): number => {
  if (n < min || n > max) throw new RangeError(`Value ${n} out of range [${min}, ${max}]`);
  return n;
};

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step: ${stepStr}`);

    const [from, to] = base === "*"
      ? [min, max]
      : base.includes("-")
        ? base.split("-").map(Number)
        : (() => { throw new SyntaxError(`Invalid step base: ${base}`); })();

    clamp(from, min, max);
    clamp(to,   min, max);
    return range(from, to, step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [a, b] = segment.split("-").map(Number);
    clamp(a, min, max);
    clamp(b, min, max);
    if (a > b) throw new RangeError(`Invalid range: ${segment}`);
    return range(a, b);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Literal
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid value: ${segment}`);
  return [clamp(n, min, max)];
};

const parseField = (expr: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];
  const values = expr
    .split(",")
    .flatMap(seg => parseSegment(seg.trim(), min, max));

  return [...new Set(values)].sort((a, b) => a - b);
};

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = (
    ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as CronField[]
  ).map((field, i) => parseField(fields[i], field));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldRange = { min: number; max: number };

const FIELD_RANGES: Record<keyof CronResult, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both = Sunday
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function expandRange(start: number, end: number, range: FieldRange): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end}`);
  }
  clamp(start, range.min, range.max);
  clamp(end, range.min, range.max);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, range: FieldRange): number[] {
  // Wildcard
  if (segment === "*") {
    return Array.from(
      { length: range.max - range.min + 1 },
      (_, i) => range.min + i
    );
  }

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);
    }

    let base: number[];
    if (left === "*") {
      base = Array.from(
        { length: range.max - range.min + 1 },
        (_, i) => range.min + i
      );
    } else if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      base = expandRange(parseInt(startStr, 10), parseInt(endStr, 10), range);
    } else {
      const start = parseInt(left, 10);
      clamp(start, range.min, range.max);
      base = Array.from(
        { length: range.max - start + 1 },
        (_, i) => start + i
      );
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    return expandRange(parseInt(startStr, 10), parseInt(endStr, 10), range);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid cron field value: "${segment}"`);
  }
  return [clamp(value, range.min, range.max)];
}

function parseField(field: string, range: FieldRange): number[] {
  // Comma-separated list
  const segments = field.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), range)) {
      values.add(value);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Normalize 7 (Sunday) to 0
  const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    const range = FIELD_RANGES[name];
    result[name] = parseField(fields[i], range);
  }

  result.dayOfWeek = normalizeDayOfWeek(result.dayOfWeek);

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

const isPlainObject = (value: unknown): value is NestedObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype ||
  (value !== null && typeof value === "object" && !Array.isArray(value) && Object.getPrototypeOf(value) === null);

const flattenObject = (
  input: unknown,
  maxDepth: number = 100
): FlattenedObject => {
  if (input === null || input === undefined) {
    return {};
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    throw new TypeError(
      `Expected a plain object, got: ${Array.isArray(input) ? "Array" : typeof input}`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  const recurse = (current: unknown, prefix: string, depth: number): void => {
    if (depth > maxDepth) {
      throw new RangeError(
        `Object exceeds maximum allowed depth of ${maxDepth}. Possible circular structure or deeply nested object.`
      );
    }

    if (current === null || current === undefined) {
      result[prefix] = current as null | undefined;
      return;
    }

    if (typeof current !== "object") {
      result[prefix] = current as Primitive;
      return;
    }

    if (Array.isArray(current)) {
      // Treat arrays as leaf values — store them stringified to avoid silent data loss
      result[prefix] = JSON.stringify(current);
      return;
    }

    if (seen.has(current as object)) {
      throw new TypeError(
        `Circular reference detected at key: "${prefix}"`
      );
    }

    seen.add(current as object);

    const keys = Object.keys(current as object);

    if (keys.length === 0) {
      // Empty object — store as leaf if it has a prefix, skip if root
      if (prefix !== "") {
        result[prefix] = "{}";
      }
      seen.delete(current as object);
      return;
    }

    for (const key of keys) {
      if (typeof key !== "string") {
        // Symbol keys are skipped; numeric keys from Object.keys are already strings
        continue;
      }

      // Sanitize key: reject keys containing dots to prevent ambiguous paths
      const sanitizedKey = key.includes(".")
        ? key.replace(/\./g, "\\.") // escape dots in keys
        : key;

      const nextPrefix = prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;
      const value = (current as Record<string, unknown>)[key];

      recurse(value, nextPrefix, depth + 1);
    }

    seen.delete(current as object);
  };

  recurse(input, "", 0);

  return result;
};

export default flattenObject;

const FIELD_RANGES = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
} as const;

type Field = keyof typeof FIELD_RANGES;

const FIELDS: Field[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function expand(expr: string, min: number, max: number): number[] {
  if (expr === "*") return Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${expr}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes(",")) {
    return expr.split(",").flatMap(part => expand(part.trim(), min, max));
  }

  if (expr.includes("-")) {
    const [a, b] = expr.split("-").map(Number);
    if (isNaN(a) || isNaN(b) || a > b) throw new Error(`Invalid range: ${expr}`);
    if (a < min || b > max) throw new Error(`Range ${expr} out of bounds [${min},${max}]`);
    return Array.from({ length: b - a + 1 }, (_, i) => i + a);
  }

  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${expr}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min},${max}]`);
  return [n];
}

export default function parseCron(cron: string): Record<Field, number[]> {
  const parts = cron.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  return Object.fromEntries(
    FIELDS.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, [...new Set(expand(parts[i], min, max))].sort((a, b) => a - b)];
    })
  ) as Record<Field, number[]>;
}

