  dayOfWeek:  [0,  6],
};

const FIELDS: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const range = (from: number, to: number, step = 1): number[] =>
  Array.from({ length: Math.floor((to - from) / step) + 1 }, (_, i) => from + i * step);

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  return value;
};

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);
    const [from, to] = rangePart === "*" ? [min, max] : rangePart.split("-").map(Number);
    return range(clamp(from, min, max), clamp(to ?? from, min, max), step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [from, to] = segment.split("-").map(Number);
    return range(clamp(from, min, max), clamp(to, min, max));
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Literal
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron token: ${segment}`);
  return [clamp(value, min, max)];
};

const parseField = (expr: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];
  const values = expr
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), min, max));
  return [...new Set(values)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  return Object.fromEntries(
    FIELDS.map((field, i) => [field, parseField(parts[i], field)])
  ) as CronResult;
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = Record<string, Primitive>;

const flattenObject = (
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject =>
  Object.entries(obj).reduce((acc, [key, value]) => {
    const path = prefix ? `${prefix}.${key}` : key;

    if (Array.isArray(value)) {
      value.forEach((item, i) =>
        typeof item === "object" && item !== null
          ? flattenObject(item as NestedObject, `${path}.${i}`, acc)
          : (acc[`${path}.${i}`] = item as Primitive)
      );
    } else if (typeof value === "object" && value !== null) {
      flattenObject(value as NestedObject, path, acc);
    } else {
      acc[path] = value as Primitive;
    }

    return acc;
  }, result);

export default flattenObject;

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;
    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      flattenObject(value as Record<string, unknown>, path, result);
    } else {
      result[path] = value;
    }
  }
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  // Allow 0–7 during parse; 7 is normalized to 0 (both = Sunday)
  dayOfWeek: { min: 0, max: 7 },
} as const satisfies Record<keyof CronFields, FieldRange>;

function assertInteger(raw: string, range: FieldRange): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected an integer, got: "${raw}"`);
  }
  const n = parseInt(trimmed, 10);
  if (n < range.min || n > range.max) {
    throw new Error(
      `Value ${n} is out of range [${range.min}–${range.max}]`
    );
  }
  return n;
}

function expandStep(base: string, stepStr: string, range: FieldRange): number[] {
  if (!/^\d+$/.test(stepStr)) {
    throw new Error(`Invalid step value: "${stepStr}"`);
  }
  const step = parseInt(stepStr, 10);
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got: ${step}`);
  }

  let start: number;
  let end: number;

  if (base === "*") {
    start = range.min;
    end = range.max;
  } else if (base.includes("-")) {
    const rangeParts = base.split("-");
    if (rangeParts.length !== 2) {
      throw new Error(`Invalid range in step expression: "${base}"`);
    }
    start = assertInteger(rangeParts[0], range);
    end = assertInteger(rangeParts[1], range);
    if (start > end) {
      throw new Error(
        `Range start (${start}) must not exceed end (${end})`
      );
    }
  } else {
    start = assertInteger(base, range);
    end = range.max;
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  if (values.length === 0) {
    throw new Error(`Step expression "${base}/${stepStr}" produced no values`);
  }
  return values;
}

function expandRange(raw: string, range: FieldRange): number[] {
  const parts = raw.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range expression: "${raw}"`);
  }
  const start = assertInteger(parts[0], range);
  const end = assertInteger(parts[1], range);
  if (start > end) {
    throw new Error(
      `Range start (${start}) must not exceed end (${end})`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange): number[] {
  if (segment === "") {
    throw new Error(`Empty segment encountered`);
  }

  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const base = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);
    if (base === "" || stepStr === "") {
      throw new Error(`Malformed step expression: "${segment}"`);
    }
    return expandStep(base, stepStr, range);
  }

  if (segment === "*") {
    const values: number[] = [];
    for (let i = range.min; i <= range.max; i++) {
      values.push(i);
    }
    return values;
  }

  if (segment.includes("-")) {
    return expandRange(segment, range);
  }

  return [assertInteger(segment, range)];
}

function parseField(field: string, range: FieldRange): number[] {
  if (typeof field !== "string" || field.trim() === "") {
    throw new Error(`Field must be a non-empty string, got: ${JSON.stringify(field)}`);
  }

  const segments = field.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new Error(`Empty item in comma-separated list: "${field}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), range)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // 7 is a non-standard alias for Sunday (0); deduplicate after mapping
  const mapped = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(mapped)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, got: ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields as [
    string,
    string,
    string,
    string,
    string,
  ];

  return {
    minute: parseField(minuteRaw, FIELD_RANGES.minute),
    hour: parseField(hourRaw, FIELD_RANGES.hour),
    dayOfMonth: parseField(domRaw, FIELD_RANGES.dayOfMonth),
    month: parseField(monthRaw, FIELD_RANGES.month),
    dayOfWeek: normalizeDayOfWeek(
      parseField(dowRaw, FIELD_RANGES.dayOfWeek)
    ),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${stepStr}`);

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end   = clamp(parseInt(endStr,   10), min, max);
      base = range(start, end);
    } else {
      const start = clamp(parseInt(rangePart, 10), min, max);
      base = range(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron token: "${segment}"`);
  return [clamp(value, min, max)];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) {
      // Normalize Sunday: both 0 and 7 map to 0 for dayOfWeek
      values.add(field === "dayOfWeek" && v === 7 ? 0 : v);
    }
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Cron expression must be a string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = Record<string, Primitive>;

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      flattenObject(value as NestedObject, path, result);
    } else {
      result[path] = value as Primitive;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function flattenObject(
  input: NestedObject,
  prefix: string = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (input === null || typeof input !== "object" || Array.isArray(input)) {
    if (prefix) {
      result[prefix] = input as Primitive | Array<unknown>;
    }
    return result;
  }

  const keys = Object.keys(input);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    const value = input[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  }, // 7 is accepted as Sunday alias
] as const;

function assertInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new RangeError(
      `Field "${fieldName}": expected integer, got "${trimmed}"`
    );
  }
  return parseInt(trimmed, 10);
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  fieldName: string,
  context: string
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Field "${fieldName}" ${context}: value ${value} is outside valid range [${min}, ${max}]`
    );
  }
}

function expandSequence(
  start: number,
  end: number,
  step: number,
  fieldName: string
): number[] {
  if (step < 1) {
    throw new RangeError(
      `Field "${fieldName}": step value must be >= 1, got ${step}`
    );
  }
  if (start > end) {
    throw new RangeError(
      `Field "${fieldName}": range start ${start} exceeds end ${end}`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parsePart(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const part = raw.trim();

  if (part.length === 0) {
    throw new SyntaxError(`Field "${fieldName}": empty segment`);
  }

  // Step expression: "*/n", "a-b/n", or "a/n"
  if (part.includes("/")) {
    const slashIdx = part.indexOf("/");
    if (slashIdx === part.length - 1) {
      throw new SyntaxError(
        `Field "${fieldName}": missing step value in "${part}"`
      );
    }
    const stepStr = part.slice(slashIdx + 1);
    const step = assertInteger(stepStr, fieldName);
    if (step < 1) {
      throw new RangeError(
        `Field "${fieldName}": step must be >= 1, got ${step}`
      );
    }
    const prefix = part.slice(0, slashIdx).trim();

    if (prefix === "*") {
      return expandSequence(min, max, step, fieldName);
    }

    if (prefix.includes("-")) {
      const dashIdx = prefix.indexOf("-");
      const start = assertInteger(prefix.slice(0, dashIdx), fieldName);
      const end   = assertInteger(prefix.slice(dashIdx + 1), fieldName);
      assertInRange(start, min, max, fieldName, "range start");
      assertInRange(end,   min, max, fieldName, "range end");
      return expandSequence(start, end, step, fieldName);
    }

    // "n/step" — start at n, step to max
    const start = assertInteger(prefix, fieldName);
    assertInRange(start, min, max, fieldName, "step origin");
    return expandSequence(start, max, step, fieldName);
  }

  // Wildcard
  if (part === "*") {
    return expandSequence(min, max, 1, fieldName);
  }

  // Range: "a-b"
  if (part.includes("-")) {
    const dashIdx = part.indexOf("-");
    if (dashIdx === 0 || dashIdx === part.length - 1) {
      throw new SyntaxError(
        `Field "${fieldName}": malformed range "${part}"`
      );
    }
    const start = assertInteger(part.slice(0, dashIdx), fieldName);
    const end   = assertInteger(part.slice(dashIdx + 1), fieldName);
    assertInRange(start, min, max, fieldName, "range start");
    assertInRange(end,   min, max, fieldName, "range end");
    return expandSequence(start, end, 1, fieldName);
  }

  // Single integer
  const value = assertInteger(part, fieldName);
  assertInRange(value, min, max, fieldName, "value");
  return [value];
}

function parseField(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (typeof raw !== "string" || raw.trim().length === 0) {
    throw new SyntaxError(`Field "${fieldName}" is missing or empty`);
  }

  const segments = raw.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    if (segment.trim().length === 0) {
      throw new SyntaxError(
        `Field "${fieldName}": empty segment in comma-separated list`
      );
    }
    for (const v of parsePart(segment, min, max, fieldName)) {
      seen.add(v);
    }
  }

  // Normalise dayOfWeek: 7 is a widely-accepted alias for Sunday (0)
  if (fieldName === "dayOfWeek" && seen.has(7)) {
    seen.delete(7);
    seen.add(0);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expression must be a string`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("parseCron: expression is empty");
  }

  // Collapse runs of whitespace so "*/15  9-17  *  *  1-5" is still valid
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `parseCron: expected exactly 5 fields, got ${fields.length} in "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronFields;
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new CronParseError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function rangeArray(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard: "*"
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step value: "*/N" or "start-end/N"
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const base = segment.slice(0, slashIndex);
    const stepStr = segment.slice(slashIndex + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new CronParseError(
        `Invalid step value "${stepStr}" in field "${fieldName}"`
      );
    }

    let rangeMin: number;
    let rangeMax: number;

    if (base === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (base.includes("-")) {
      const parts = base.split("-");
      rangeMin = parseInt(parts[0], 10);
      rangeMax = parseInt(parts[1], 10);
      if (isNaN(rangeMin) || isNaN(rangeMax)) {
        throw new CronParseError(`Invalid range "${base}" in field "${fieldName}"`);
      }
      assertInRange(rangeMin, min, max, fieldName);
      assertInRange(rangeMax, min, max, fieldName);
      if (rangeMin > rangeMax) {
        throw new CronParseError(
          `Range start ${rangeMin} exceeds end ${rangeMax} in field "${fieldName}"`
        );
      }
    } else {
      rangeMin = parseInt(base, 10);
      if (isNaN(rangeMin)) {
        throw new CronParseError(`Invalid step base "${base}" in field "${fieldName}"`);
      }
      assertInRange(rangeMin, min, max, fieldName);
      rangeMax = max;
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // Range: "start-end"
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new CronParseError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) {
      throw new CronParseError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) {
      throw new CronParseError(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }
    return rangeArray(start, end);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new CronParseError(
      `Unrecognised token "${segment}" in field "${fieldName}"`
    );
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // Comma-separated list: expand each segment and merge
  const segments = raw.split(",");
  const seen = new Set<number>();
  const values: number[] = [];

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new CronParseError(`Empty segment in field "${name}"`);
    }
    for (const v of parseSegment(trimmed, min, max, name)) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new CronParseError(
      `Expected 5 fields but received ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(parts[i], config);
  }

  return result;
}

const FIELD_RANGES = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
} as const;

type FieldName = keyof typeof FIELD_RANGES;
type CronResult = Record<FieldName, number[]>;

function parseField(expr: string, min: number, max: number): number[] {
  const all = () => Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (expr === "*") return all();

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${expr}`);
    return all().filter(v => (v - min) % step === 0);
  }

  if (expr.includes(",")) {
    return expr.split(",").flatMap(part => parseField(part.trim(), min, max));
  }

  if (expr.includes("-")) {
    const [a, b] = expr.split("-").map(Number);
    if (isNaN(a) || isNaN(b) || a > b || a < min || b > max)
      throw new Error(`Invalid range: ${expr}`);
    return Array.from({ length: b - a + 1 }, (_, i) => i + a);
  }

  const n = parseInt(expr, 10);
  if (isNaN(n) || n < min || n > max) throw new Error(`Value out of range: ${expr}`);
  return [n];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error("Cron expression must have exactly 5 fields");

  const fields = Object.keys(FIELD_RANGES) as FieldName[];
  return Object.fromEntries(
    fields.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, [...new Set(parseField(parts[i], min, max))].sort((a, b) => a - b)];
    })
  ) as CronResult;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const sanitizedKey = key.includes(".") ? `[${key}]` : key;
    const newPrefix = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newPrefix, result);
    } else {
      result[newPrefix] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const expandRange = (start: number, end: number, step = 1): number[] => {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const parseSegment = (segment: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  // Step with wildcard: */n
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    return expandRange(min, max, step);
  }

  // Pure wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Range with optional step: a-b or a-b/n
  if (/^\d+-\d+(\/\d+)?$/.test(segment)) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Range start ${start} exceeds end ${end} in field "${field}"`);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    return expandRange(start, end, step);
  }

  // Plain integer
  if (/^\d+$/.test(segment)) {
    const value = parseInt(segment, 10);
    // dayOfWeek special case: 7 is also Sunday (alias for 0)
    if (field === "dayOfWeek" && value === 7) return [0];
    return [clamp(value, min, max)];
  }

  throw new Error(`Unrecognized cron segment "${segment}" for field "${field}"`);
};

const parseField = (expr: string, field: CronField): number[] => {
  const parts = expr.split(",");
  const allValues = new Set<number>();

  for (const part of parts) {
    const values = parseSegment(part.trim(), field);
    for (const v of values) allValues.add(v);
  }

  return [...allValues].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined) {
    return result;
  }

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      const nested = value as NestedObject;

      if (Object.keys(nested).length === 0) {
        result[flatKey] = {} as unknown as Primitive;
      } else {
        flattenObject(nested, flatKey, result);
      }
    } else {
      result[flatKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const range = (from: number, to: number, step = 1): number[] =>
  Array.from({ length: Math.floor((to - from) / step) + 1 }, (_, i) => from + i * step);

const clamp = (n: number, min: number, max: number): number => {
  if (n < min || n > max) throw new RangeError(`Value ${n} out of range [${min}, ${max}]`);
  return n;
};

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step: ${stepStr}`);
    const from = base === "*" ? min : clamp(parseInt(base, 10), min, max);
    return range(from, max, step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = clamp(parseInt(fromStr, 10), min, max);
    const to   = clamp(parseInt(toStr,   10), min, max);
    if (from > to) throw new RangeError(`Invalid range: ${segment}`);
    return range(from, to);
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid value: ${segment}`);
  return [clamp(n, min, max)];
};

const parseField = (expr: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];
  const values = expr
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), min, max));
  return [...new Set(values)].sort((a, b) => a - b);
};

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  return {
    minute:     parseField(minuteExpr,     "minute"),
    hour:       parseField(hourExpr,       "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month:      parseField(monthExpr,      "month"),
    dayOfWeek:  parseField(dayOfWeekExpr,  "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj) as string;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const value = (obj as Record<string, unknown>)[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      result[newKey] = JSON.stringify(value);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

const flattenObject = (
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> => {
  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;
    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      flattenObject(value as Record<string, unknown>, path, result);
    } else {
      result[path] = value;
    }
  }
  return result;
};

export default flattenObject;

const FIELD_RANGES = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
] as const;

type CronResult = Record<(typeof FIELD_RANGES)[number]["name"], number[]>;

const range = (min: number, max: number, step = 1): number[] =>
  Array.from({ length: Math.floor((max - min) / step) + 1 }, (_, i) => min + i * step);

const clamp = (v: number, min: number, max: number) => {
  if (v < min || v > max) throw new Error(`Value ${v} out of range [${min},${max}]`);
  return v;
};

const parseField = (field: string, min: number, max: number): number[] => {
  if (field === "*") return range(min, max);

  if (field.includes(","))
    return [...new Set(field.split(",").flatMap(f => parseField(f, min, max)))].sort((a, b) => a - b);

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2));
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${field}`);
    return range(min, max, step);
  }

  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${field}`);
    const [lo, hi] = rangePart.split("-").map(Number);
    return range(clamp(lo, min, max), clamp(hi, min, max), step);
  }

  if (field.includes("-")) {
    const [lo, hi] = field.split("-").map(Number);
    return range(clamp(lo, min, max), clamp(hi, min, max));
  }

  const v = parseInt(field);
  if (isNaN(v)) throw new Error(`Invalid value: ${field}`);
  return [clamp(v, min, max)];
};

export default function parseCron(expr: string): CronResult {
  const fields = expr.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);
  return Object.fromEntries(
    FIELD_RANGES.map(({ name, min, max }, i) => [name, parseField(fields[i], min, max)])
  ) as CronResult;
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = ""
): Record<string, unknown> {
  return Object.entries(obj).reduce((acc, [key, val]) => {
    const path = prefix ? `${prefix}.${key}` : key;
    if (val !== null && typeof val === "object" && !Array.isArray(val)) {
      Object.assign(acc, flattenObject(val as Record<string, unknown>, path));
    } else {
      acc[path] = val;
    }
    return acc;
  }, {} as Record<string, unknown>);
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

const INTEGER_RE = /^\d+$/;

function isValidInteger(s: string): boolean {
  return INTEGER_RE.test(s) && s.length > 0;
}

function parseInteger(s: string, context: string): number {
  if (!isValidInteger(s)) {
    throw new Error(`Expected an integer, got "${s}" in "${context}"`);
  }
  const n = parseInt(s, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow: "${s}" in "${context}"`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of allowed range [${min}, ${max}] in "${context}"`);
  }
}

function buildRange(start: number, end: number, step: number): number[] {
  if (start > end) {
    throw new Error(`Range start ${start} must not exceed end ${end}`);
  }
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseAtom(atom: string, min: number, max: number): number[] {
  // Atom is a single token with no commas.
  // Valid forms: "*", "n", "n-m", "*/s", "n/s", "n-m/s"

  const slashIdx = atom.indexOf("/");

  if (slashIdx !== -1) {
    const stepStr = atom.slice(slashIdx + 1);
    const rangePart = atom.slice(0, slashIdx);

    if (stepStr === "" || rangePart === "") {
      throw new Error(`Malformed step expression "${atom}"`);
    }

    const step = parseInteger(stepStr, atom);
    if (step <= 0) {
      throw new Error(`Step must be positive, got ${step} in "${atom}"`);
    }

    if (rangePart === "*") {
      return buildRange(min, max, step);
    }

    const dashIdx = rangePart.indexOf("-");
    if (dashIdx > 0) {
      const startStr = rangePart.slice(0, dashIdx);
      const endStr   = rangePart.slice(dashIdx + 1);
      const start    = parseInteger(startStr, atom);
      const end      = parseInteger(endStr,   atom);
      assertInRange(start, min, max, atom);
      assertInRange(end,   min, max, atom);
      return buildRange(start, end, step);
    }

    // "n/s" — start at n, step to max
    const start = parseInteger(rangePart, atom);
    assertInRange(start, min, max, atom);
    return buildRange(start, max, step);
  }

  if (atom === "*") {
    return buildRange(min, max, 1);
  }

  const dashIdx = atom.indexOf("-");
  if (dashIdx > 0) {
    // Ensure we don't treat a leading "-" as a range separator.
    const startStr = atom.slice(0, dashIdx);
    const endStr   = atom.slice(dashIdx + 1);
    const start    = parseInteger(startStr, atom);
    const end      = parseInteger(endStr,   atom);
    assertInRange(start, min, max, atom);
    assertInRange(end,   min, max, atom);
    return buildRange(start, end, 1);
  }

  const value = parseInteger(atom, atom);
  assertInRange(value, min, max, atom);
  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  if (!field || field.trim() === "") {
    throw new Error("Empty cron field");
  }

  const atoms = field.split(",");

  if (atoms.some((a) => a.trim() === "")) {
    throw new Error(`Trailing or double comma in field "${field}"`);
  }

  const values = new Set<number>();

  for (const atom of atoms) {
    const trimmed = atom.trim();
    if (trimmed === "") {
      throw new Error(`Empty atom in field "${field}"`);
    }
    for (const v of parseAtom(trimmed, min, max)) {
      values.add(v);
    }
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    const raw = parts[i];

    try {
      let values = parseField(raw, min, max);

      // Normalize Sunday: both 0 and 7 represent Sunday; canonicalize to 0.
      if (name === "dayOfWeek") {
        const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
        values = [...normalized].sort((a, b) => a - b);
      }

      result[name] = values;
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid "${name}" field (field ${i + 1}): ${msg}`);
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | Record<string, unknown>,
  prefix: string = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
      return result;
    }
    for (let i = 0; i < obj.length; i++) {
      const key = prefix ? `${prefix}.${i}` : String(i);
      const value = obj[i];
      if (value !== null && typeof value === "object") {
        flattenObject(value as Record<string, unknown>, key, result);
      } else {
        result[key] = value as Primitive;
      }
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const sanitizedKey = key.includes(".") ? `[${key}]` : key;
    const fullKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = (obj as Record<string, unknown>)[key];

    if (value !== null && typeof value === "object") {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive | Date | unknown[] };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Error) return false;
  if (Array.isArray(value)) return false;
  return true;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: Record<string, unknown>,
  seen: Set<object>
): void {
  if (seen.has(obj)) {
    // Circular reference detected — skip rather than infinite-loop
    result[prefix] = "[Circular]";
    return;
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty object leaf — preserve it so callers know the key exists
    if (prefix !== "") {
      result[prefix] = {};
    }
    seen.delete(obj);
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value: unknown = obj[key];
    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenObjectInternal(value as NestedObject, newKey, result, seen);
    } else {
      // Leaf: primitive, Date, Array, RegExp, Error, null, undefined, function, etc.
      if (typeof value !== "function" && typeof value !== "symbol") {
        result[newKey] = value;
      }
      // Functions and symbols are silently dropped — they can't be serialised
      // and have no meaningful dot-notation representation
    }
  }

  seen.delete(obj);
}

export default function flattenObject(
  input: unknown,
  prefix = ""
): Record<string, unknown> {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: expected a plain object, received ${
        input === null ? "null" : typeof input
      }`
    );
  }

  if (typeof prefix !== "string") {
    throw new TypeError(
      `flattenObject: prefix must be a string, received ${typeof prefix}`
    );
  }

  const result: Record<string, unknown> = {};
  const seen = new Set<object>();

  flattenObjectInternal(input as NestedObject, prefix, result, seen);

  return result;
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | Date | RegExp | Function | unknown[];
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Error) return false;
  if (Array.isArray(value)) return false;
  return true;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as FlatValue;
    }
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;
    const value = obj[key];

    if (isPlainObject(value)) {
      if (seen.has(value)) {
        result[fullKey] = "[Circular]";
        continue;
      }
      seen.add(value);
      flattenObjectInternal(value, fullKey, result, seen);
      seen.delete(value);
    } else {
      result[fullKey] = value as FlatValue;
    }
  }
}

export default function flattenObject(input: unknown): FlatObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();
  seen.add(input);
  flattenObjectInternal(input, "", result, seen);
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

const flattenObject = (
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject =>
  Object.entries(obj).reduce((acc, [key, value]) => {
    const path = prefix ? `${prefix}.${key}` : key;

    if (Array.isArray(value)) {
      value.forEach((item, i) => {
        const arrPath = `${path}.${i}`;
        typeof item === "object" && item !== null
          ? flattenObject(item as NestedObject, arrPath, acc)
          : (acc[arrPath] = item as Primitive);
      });
    } else if (typeof value === "object" && value !== null) {
      flattenObject(value as NestedObject, path, acc);
    } else {
      acc[path] = value;
    }

    return acc;
  }, result);

export default flattenObject;
